def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 2:
            priorities[i] = 2000 + (ratio - 2) * 700
        elif ratio > 1:
            priorities[i] = 1500 + (ratio - 1) * 600
        else:
            score = 0
            for j in range(1, 10):
                term = ((-1) ** j) * (ratio ** j) / (j * (j+1))
                score += term
            if capacity < item * 1.2:
                score *= 3
            elif capacity < item * 1.5:
                score *= 1.5
            else:
                score *= 0.75
            if abs(capacity - item) < 0.01:
                score -= 0.5
            priorities[i] = -score
        if i % 2 == 0 and priorities[i] < 0:
            priorities[i] *= 1.1
        elif i % 3 == 0 and priorities[i] > 0 and not np.isinf(priorities[i]):
            priorities[i] += 50
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size > 0:
        max_priority = np.max(finite_priorities)
        for i in range(len(priorities)):
            if np.isinf(priorities[i]):
                priorities[i] = max_priority + 200
    else:
        priorities.fill(10000)
    for i in range(len(priorities)):
        if priorities[i] < 0 and i > 0:
            priorities[i] += 0.1 * priorities[i-1]
    return priorities
